
-- Step A: Add new columns
ALTER TABLE public.email_templates
ADD COLUMN IF NOT EXISTS category text DEFAULT 'general',
ADD COLUMN IF NOT EXISTS thumbnail_url text,
ADD COLUMN IF NOT EXISTS required_variables jsonb DEFAULT '[]'::jsonb;

-- Update existing system templates
UPDATE public.email_templates SET category = 'onboarding', required_variables = '["isim"]'::jsonb WHERE name = 'Hoş Geldin (Kurumsal)' AND is_system = true;
UPDATE public.email_templates SET category = 'retention', required_variables = '["isim"]'::jsonb WHERE name = 'Antrenman Programı Hatırlatması' AND is_system = true;

